445:	if !ok {
446:		return fmt.Errorf("secret %s/%s does not contain key %s", namespace, DefaultRedisInitialPasswordSecretName, DefaultRedisInitialPasswordKey)
447:	}
448:	redisOptions.Password = string(secret.Data[DefaultRedisInitialPasswordKey])
449:	return nil
450:}

